// ── Due-Date Reminder Engine — classification & dedup ──────────────
// Pure core JS. Uses Luxon (DateTime) which n8n injects globally.
// WHY Luxon: whole-calendar-day math in the workflow timezone avoids
// UTC off-by-one bugs that plain `new Date()` subtraction produces.

// ===== EDITABLE CONSTANTS ==========================================
const REMINDER_WINDOW_DAYS = 3;   // days ahead that count as "due soon"
const DONE_STATUS = 'Done';       // Status value that means "ignore"
const DATE_FMT = 'yyyy-MM-dd';    // sheet date format (YYYY-MM-DD)
// ===================================================================

// "today" as a date-only anchor in the workflow's timezone.
// WHY startOf('day'): strips the clock time so diffs are full days.
const today = DateTime.now().startOf('day'); // DateTime.now() already honours the workflow timezone
const todayStr = today.toFormat(DATE_FMT);

const out = [];

for (const item of $input.all()) {
  const row = item.json;

  // Skip blank spacer rows that have no due date at all.
  const rawDue = (row.DueDate ?? '').toString().trim();
  if (!rawDue) continue;

  // Skip anything already marked finished.
  const status = (row.Status ?? '').toString().trim();
  if (status === DONE_STATUS) continue;

  // ── DEDUP GUARD ────────────────────────────────────────────────
  // If this row was already reminded today, do nothing for it now.
  const notifiedOn = (row.NotifiedOn ?? '').toString().trim();
  if (notifiedOn === todayStr) continue;

  // Parse the due date as a date-only value in the same timezone.
  const due = DateTime.fromFormat(rawDue, DATE_FMT, { zone: today.zoneName }).startOf('day');
  if (!due.isValid) continue; // WHY: bad date strings shouldn't crash the run

  // Whole-day difference: negative = past, 0 = today, positive = future.
  const daysUntilDue = Math.round(due.diff(today, 'days').days);

  // Classify; rows outside the window are left alone.
  let reminderType = null;
  if (daysUntilDue < 0) reminderType = 'overdue';
  else if (daysUntilDue === 0) reminderType = 'due_today';
  else if (daysUntilDue <= REMINDER_WINDOW_DAYS) reminderType = 'due_soon';
  if (!reminderType) continue;

  // Human-readable line reused by both email and Slack.
  const overdueDays = Math.abs(daysUntilDue);
  const phrase =
    reminderType === 'overdue'
      ? `is OVERDUE by ${overdueDays} day${overdueDays === 1 ? '' : 's'}`
      : reminderType === 'due_today'
      ? 'is due TODAY'
      : `is due in ${daysUntilDue} day${daysUntilDue === 1 ? '' : 's'}`;

  const title = (row.Title ?? 'Untitled item').toString().trim();
  const message = `"${title}" ${phrase} (due ${rawDue}).`;

  out.push({
    json: {
      Title: title,
      Email: (row.Email ?? '').toString().trim(),
      DueDate: rawDue,
      daysUntilDue,
      reminderType,
      isOverdue: reminderType === 'overdue',
      row_number: row.row_number, // WHY: needed to update the exact row later
      todayStr,
      message,
    },
  });
}

return out;

